#include <stdio.h>
#include <stdint.h>
const int MOD = 998244353;
long long modpow(long long a, long long e){
    long long r=1;
    while(e){
        if(e&1) r=r*a%MOD;
        a=a*a%MOD;
        e>>=1;
    }
    return r;
}
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    const int MAX = 2005;
    static long long fact[MAX], invfact[MAX];
    fact[0]=1;
    for(int i=1;i<MAX;i++) fact[i]=fact[i-1]*i%MOD;
    invfact[MAX-1]=modpow(fact[MAX-1], MOD-2);
    for(int i=MAX-2;i>=0;i--) invfact[i]=invfact[i+1]*(i+1)%MOD;
    while(T--){
        long long N,M; scanf("%lld %lld",&N,&M);
        long long L = N+M-1;
        if(L%2){
            printf("0\n");
            continue;
        }
        long long paths = fact[N+M-2]*invfact[N-1]%MOD*invfact[M-1]%MOD;
        long long waysOnPath = fact[L]*invfact[L/2]%MOD*invfact[L/2]%MOD;
        long long rest = modpow(2, N*M - L);
        long long ans = paths * waysOnPath % MOD * rest % MOD;
        printf("%lld\n", ans);
    }
    return 0;
}

