import java.io.*;
import java.util.*;

public class Main {
    static final long MOD = 998244353L;
    static long modPow(long a, long e){
        long r = 1;
        while(e>0){
            if((e & 1) == 1) r = r * a % MOD;
            a = a * a % MOD;
            e >>= 1;
        }
        return r;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        final int MAX = 2005;
        long[] fact = new long[MAX];
        long[] invFact = new long[MAX];
        fact[0] = 1;
        for(int i=1;i<MAX;i++) fact[i] = fact[i-1] * i % MOD;
        invFact[MAX-1] = modPow(fact[MAX-1], MOD-2);
        for(int i=MAX-2;i>=0;i--) invFact[i] = invFact[i+1] * (i+1) % MOD;
        StringBuilder sb = new StringBuilder();
        for(int tc=0; tc<T; tc++){
            st = new StringTokenizer(br.readLine());
            long N = Long.parseLong(st.nextToken());
            long M = Long.parseLong(st.nextToken());
            long L = N + M - 1;
            if((L & 1) == 1){
                sb.append(0).append('\n');
                continue;
            }
            long paths = fact[(int)(N+M-2)] * invFact[(int)(N-1)] % MOD * invFact[(int)(M-1)] % MOD;
            long waysOnPath = fact[(int)L] * invFact[(int)(L/2)] % MOD * invFact[(int)(L/2)] % MOD;
            long rest = modPow(2L, N*M - L);
            long ans = paths * waysOnPath % MOD * rest % MOD;
            sb.append(ans).append('\n');
        }
        System.out.print(sb.toString());
    }
}

