const fs = require('fs');
const MOD = 998244353n;
function modPow(a, e){
  let r = 1n;
  while(e > 0n){
    if(e & 1n) r = r * a % MOD;
    a = a * a % MOD;
    e >>= 1n;
  }
  return r;
}
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if(input.length===0){process.exit(0);} 
const T = Number(input[idx++]);
const MAX = 2005;
const fact = new Array(MAX).fill(0n);
const invFact = new Array(MAX).fill(0n);
fact[0] = 1n;
for(let i=1;i<MAX;i++) fact[i] = fact[i-1] * BigInt(i) % MOD;
invFact[MAX-1] = modPow(fact[MAX-1], MOD-2n);
for(let i=MAX-2;i>=0;i--) invFact[i] = invFact[i+1] * BigInt(i+1) % MOD;
function nCr(n, r){
  if(r<0 || r>n) return 0n;
  return fact[n] * invFact[r] % MOD * invFact[n-r] % MOD;
}
let out = [];
for(let t=0;t<T;t++){
  const N = Number(input[idx++]);
  const M = Number(input[idx++]);
  const L = N + M - 1;
  if(L % 2 === 1){
    out.push('0');
    continue;
  }
  const paths = nCr(N+M-2, N-1);
  const waysOnPath = nCr(L, Math.floor(L/2));
  const rest = modPow(2n, BigInt(N*M - L));
  const ans = paths * waysOnPath % MOD * rest % MOD;
  out.push(ans.toString());
}
console.log(out.join('\n'));
